# E2e tests for category: metadata
# Generated by html-to-markdown-e2e-generator — do not edit manually.

defmodule HtmlToMarkdown.MetadataTest do
  use ExUnit.Case

  test "metadata_author_meta: Extract author from <meta name='author'> tag" do
    html =
      "<html><head><title>Page</title><meta name=\"author\" content=\"Jane Doe\"></head><body><p>Content</p></body></html>"

    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.trim(content) != ""
  end

  test "metadata_canonical_url: Extract canonical URL from <link rel='canonical'> tag" do
    html =
      "<html><head><title>Page</title><link rel=\"canonical\" href=\"https://example.com/canonical-page\"></head><body><p>Content</p></body></html>"

    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.trim(content) != ""
  end

